const d=`{% block sw_order_delivery_metadata %} <mt-card class="sw-order-delivery-metadata" position-identifier="sw-order-delivery-metadata" :title="title" :is-loading="isLoading" > {% block sw_order_delivery_metadata_deliveries %} <sw-container columns="repeat(auto-fit, minmax(250px, 1fr))" gap="0 30px" > {% block sw_order_delivery_metadata_deliveries_data %} <sw-description-list> {% block sw_order_delivery_metadata_shipping_method %} <dt>{{ $t('sw-order.detailDeliveries.labelShippingMethod') }}</dt> <dd>{{ delivery.shippingMethod.translated.name }}</dd> {% endblock %} {% block sw_order_delivery_metadata_delivery_date %} <dt>{{ $t('sw-order.detailDeliveries.labelDeliveryDate') }}</dt> <dd>{{ dateFilter(delivery.shippingDateEarliest, { month: '2-digit', day: '2-digit' }) }}</dd> {% endblock %} {% block sw_order_delivery_metadata_shipping_costs %} <dt>{{ $t('sw-order.detailDeliveries.labelShippingCosts') }}</dt> <dd>{{ currencyFilter(order.shippingTotal, order.currency.isoCode) }}</dd> {% endblock %} {% block sw_order_delivery_metadata_slot %} {% endblock %} </sw-description-list> {% endblock %} {% block sw_order_delivery_metadata_shipping_address %} <sw-description-list> <sw-address class="sw-order-delivery-metdata__address" :headline="$t('sw-order.detailBase.headlineDeliveryAddress')" :address="delivery.shippingOrderAddress" :formatting-address="formattingAddress" /> {% block sw_order_delivery_metadata_delivery_phone_number %} <dt>{{ $t('sw-order.detailBase.labelCustomerPhoneNumber') }}</dt> <dd v-if="delivery.shippingOrderAddress.phoneNumber"> {{ delivery.shippingOrderAddress.phoneNumber }} </dd> <dd v-else> {{ $t('sw-order.detailBase.labelNoPhoneNumber') }} </dd> {% endblock %} </sw-description-list> {% endblock %} </sw-container> {% endblock %} </mt-card> {% endblock %}`,r={template:d,inject:["customSnippetApiService"],props:{delivery:{type:Object,required:!0,default:()=>{}},order:{type:Object,required:!0,default:()=>{}},title:{type:String,required:!1,default:null},isLoading:{type:Boolean,required:!1,default:!1}},data(){return{formattingAddress:""}},computed:{currencyFilter(){return Shopware.Filter.getByName("currency")},dateFilter(){return Shopware.Filter.getByName("date")}},created(){this.createdComponent()},methods:{createdComponent(){this.renderFormattingAddress()},renderFormattingAddress(){this.customSnippetApiService.render(this.delivery.shippingOrderAddress,this.delivery.shippingOrderAddress.country.addressFormat).then(e=>{this.formattingAddress=e.rendered})}}};export{r as default};
